/**
 * Fix: Implemented the main App component to connect MachineCard and ReportModal.
 */
import React, { useState, useEffect } from 'react';
import MachineCard from './components/MachineCard';
import ReportModal from './components/ReportModal';
import { MOCK_MACHINES, MOCK_CYCLE_TIMES } from './constants';
import { Language } from './types';

const App: React.FC = () => {
  const [lang, setLang] = useState<Language>('en');
  const [currentTime, setCurrentTime] = useState(new Date());
  const [selectedMachineId, setSelectedMachineId] = useState<string | null>(null);

  useEffect(() => {
    const timer = setInterval(() => setCurrentTime(new Date()), 1000);
    return () => clearInterval(timer);
  }, []);

  const handleOpenReport = (id: string) => setSelectedMachineId(id);
  const handleCloseReport = () => setSelectedMachineId(null);

  // Enriched machines with calculated metrics for demonstration
  const enrichedMachines = MOCK_MACHINES.map(m => {
    const totalFin = m.totalShiftFin;
    // Mock target for calculation demonstration
    const targetFin = 400; 
    const cycleAchievement = Math.round((totalFin / targetFin) * 100);
    return { ...m, cycleAchievement, targetFin };
  });

  const selectedMachine = enrichedMachines.find(m => m.id === selectedMachineId);

  return (
    <div className="min-h-screen bg-slate-50 dark:bg-slate-900 p-6">
      <header className="mb-8 flex flex-col md:flex-row md:items-center justify-between gap-4">
        <div>
          <h1 className="text-3xl font-black text-slate-800 dark:text-white uppercase tracking-tight">Production Monitoring</h1>
          <p className="text-slate-500 dark:text-slate-400 font-medium">{currentTime.toLocaleString()}</p>
        </div>
        <div className="flex items-center gap-4">
          <button 
            onClick={() => setLang(lang === 'en' ? 'th' : 'en')}
            className="px-4 py-2 bg-white dark:bg-slate-800 rounded-lg shadow-sm border border-slate-200 dark:border-slate-700 font-bold text-sm transition-all hover:bg-slate-50"
          >
            {lang === 'en' ? 'ไทย' : 'English'}
          </button>
        </div>
      </header>

      <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
        {enrichedMachines.map(m => (
          <MachineCard 
            key={m.id}
            machine={m}
            lang={lang}
            shift="Day"
            date={currentTime.toISOString().split('T')[0]}
            layoutRows={2}
            cycleTimes={MOCK_CYCLE_TIMES}
            currentTime={currentTime}
            onOpenReport={handleOpenReport}
          />
        ))}
      </div>

      {selectedMachine && (
        <ReportModal 
          machine={selectedMachine}
          cycleTimes={MOCK_CYCLE_TIMES}
          currentTime={currentTime}
          date={currentTime.toISOString().split('T')[0]}
          onClose={handleCloseReport}
        />
      )}
    </div>
  );
};

export default App;

/**
 * Fix: Implemented entry point to mount the React application.
 */
import React from 'react';
import { createRoot } from 'react-dom/client';
import App from './App';

const container = document.getElementById('root');
if (container) {
  const root = createRoot(container);
  root.render(
    <React.StrictMode>
      <App />
    </React.StrictMode>
  );
}

